@Component({ ... })
export class CartComponent {
  items = signal<CartItem[]>([]);
  user = signal({ name: 'Deiva', plan: 'free' });

  addItem(item: CartItem) {
    // Spread to create new array — signal detects the reference change
    this.items.update(curr => [...curr, item]);
  }

  removeItem(id: number) {
    this.items.update(curr => curr.filter(i => i.id !== id));
  }

  upgradePlan(plan: string) {
    // Spread to create new object — OnPush-safe
    this.user.update(curr => ({ ...curr, plan }));
  }
}

@Injectable({ providedIn: 'root' })
export class UserService {
  constructor(private http: HttpClient) {}

  getUser(id: number) {
    return this.http.get<{ data: User; meta: ResponseMeta }>(`/api/users/${id}`).pipe(
      map(({ data, meta }) => ({ user: data, total: meta.total }))
    );
  }
}

