// Generic immutable patch — spread-based
function patch<T extends object>(target: T, changes: Partial<T>): T {
  return { ...target, ...changes };
}

const user = { id: 1, name: 'Deiva', role: 'user', active: true };
const updated = patch(user, { role: 'admin', active: false });
// { id: 1, name: 'Deiva', role: 'admin', active: false }
// user is unchanged

// Extract own props; forward the rest to a child
interface ButtonProps {
  label: string;
  variant?: 'primary' | 'secondary';
  disabled?: boolean;
  onClick?: () => void;
}

function renderButton({ label, variant = 'primary', ...htmlAttrs }: ButtonProps) {
  // htmlAttrs = { disabled, onClick } — ready to spread onto <button>
  return { label, variant, htmlAttrs };
}

// React-style signal pair (Angular equivalent with signal)
function useCounter(initial = 0): [() => number, (n: number) => void] {
  const count = signal(initial);
  return [count, count.set];   // destructure at call site
}

const [getCount, setCount] = useCounter(10);
getCount();      // 10
setCount(20);

// Named tuple — more readable than positional
function parseDate(iso: string): { year: number; month: number; day: number } {
  const [year, month, day] = iso.split('-').map(Number);
  return { year, month, day };
}

const { year, month } = parseDate('2025-06-30');

interface Config {
  host: string;
  port: number;
  ssl?: boolean;
  timeout?: number;
}

function connect({ host, port, ssl = false, timeout = 5000 }: Config) {
  // TypeScript knows:
  // host: string, port: number, ssl: boolean, timeout: number
  return `${ssl ? 'https' : 'http'}://${host}:${port}`;
}

