// Generic rest type
function omit<T extends object, K extends keyof T>(obj: T, ...keys: K[]): Omit<T, K> {
  const result = { ...obj };
  keys.forEach(k => delete result[k]);
  return result as Omit<T, K>;
}

const withoutId = omit(user, 'id', 'password');

@Injectable({ providedIn: 'root' })
export class AppStateService {
  private state = signal<AppState>({
    user: null,
    loading: false,
    error: null,
    items: [],
  });

  loadUser(id: number) {
    this.state.update(s => ({ ...s, loading: true, error: null }));

    this.http.get<User>(`/api/users/${id}`).pipe(
      map(user => ({ ...this.state(), user, loading: false })),
      catchError(err => of({ ...this.state(), error: err.message, loading: false })),
    ).subscribe(newState => this.state.set(newState));
  }

  // Derived selectors
  user = computed(() => this.state().user);
  isLoading = computed(() => this.state().loading);
}
